import hashlib
import time
from typing import List
from dataclasses import dataclass

@dataclass
class Transaction:
    sender: str
    receiver: str
    amount: float
    signature: str = ""

@dataclass
class Block:
    index: int
    previous_hash: str
    transactions: List[Transaction]
    timestamp: float = None
    nonce: int = 0
    hash: str = ""

    def __post_init__(self):
        self.timestamp = self.timestamp or time.time()
        self.hash = self.calculate_hash()

    def calculate_merkle_root(self) -> str:
        """Calculate Merkle root of transactions."""
        if not self.transactions:
            return hashlib.sha256(b"").hexdigest()

        tx_hashes = [hashlib.sha256(
            f"{tx.sender}{tx.receiver}{tx.amount}".encode()
        ).hexdigest() for tx in self.transactions]

        while len(tx_hashes) > 1:
            if len(tx_hashes) % 2 == 1:
                tx_hashes.append(tx_hashes[-1])
            tx_hashes = [
                hashlib.sha256((tx_hashes[i] + tx_hashes[i+1]).encode()).hexdigest()
                for i in range(0, len(tx_hashes), 2)
            ]
        return tx_hashes[0]

    def calculate_hash(self) -> str:
        merkle_root = self.calculate_merkle_root()
        block_data = f"{self.index}{self.previous_hash}{merkle_root}{self.timestamp}{self.nonce}"
        return hashlib.sha256(block_data.encode()).hexdigest()

class Blockchain:
    def __init__(self):
        self.chain = []
        self.create_genesis_block()

    def create_genesis_block(self):
        genesis = Block(
            index=0,
            previous_hash="0" * 64,
            transactions=[],
            timestamp=0  # Fixed timestamp for genesis
        )
        self.chain.append(genesis)

    def validate_chain(self) -> tuple[bool, str]:
        """Validate entire blockchain integrity."""
        for i in range(1, len(self.chain)):
            current = self.chain[i]
            previous = self.chain[i - 1]

            # Verify hash calculation
            if current.hash != current.calculate_hash():
                return False, f"Block {i}: Hash mismatch"

            # Verify chain link
            if current.previous_hash != previous.hash:
                return False, f"Block {i}: Broken chain link"

        return True, "Chain is valid"

    def detect_tampering(self, block_index: int):
        """Demonstrate what happens when a block is tampered."""
        if block_index >= len(self.chain):
            return "Invalid block index"

        # Tamper with a block
        self.chain[block_index].transactions.append(
            Transaction("attacker", "attacker", 1000000)
        )

        # Validate
        is_valid, message = self.validate_chain()
        return f"After tampering: {message}"

const crypto = require('crypto');

class Block {
    constructor(index, transactions, previousHash) {
        this.index = index;
        this.timestamp = Date.now();
        this.transactions = transactions;
        this.previousHash = previousHash;
        this.nonce = 0;
        this.hash = this.calculateHash();
    }

    calculateHash() {
        const data = 
            this.index + 
            this.timestamp + 
            JSON.stringify(this.transactions) + 
            this.previousHash + 
            this.nonce;
        return crypto.createHash('sha256').update(data).digest('hex');
    }

    // Simple proof of work
    mineBlock(difficulty) {
        const target = '0'.repeat(difficulty);
        while (this.hash.substring(0, difficulty) !== target) {
            this.nonce++;
            this.hash = this.calculateHash();
        }
        console.log(`Block mined: ${this.hash}`);
    }
}

